choose.when:
select 
from wcs_profile_chain_node WITH (NOLOCK)
where warehouse_id = #{warehouseId}
  and chain_name = #{chainName}
  and enabled = 1
order by node_order

select 
from wcs_profile_chain_node
where warehouse_id = #{warehouseId}
  and chain_name = #{chainName}
  and enabled = true
order by node_order

select 
from wcs_profile_chain_node WITH (NOLOCK)
where warehouse_id = #{warehouseId}
order by chain_name, node_order

select distinct chain_name
from wcs_profile_chain_node WITH (NOLOCK)
where warehouse_id = #{warehouseId}

select distinct chain_name
from wcs_profile_chain_node
where warehouse_id = #{warehouseId}

mapper.delete:
delete from wcs_profile_chain_node
where warehouse_id = #{warehouseId}
  and chain_name = #{chainName}
